<?php namespace App\Repositories\Admission;use App\Repositories\BaseRepository;use App\Models\Admission\AdmissionEnquiry;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class AdmissionEnquiryRepository extends BaseRepository{    public function __construct(AdmissionEnquiry $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function findFollowUps(int $days = 3): Collection    {        return $this->query()->whereNotNull('follow_up_date')->whereDate('follow_up_date', '<=', now()->addDays($days))->whereNotIn('status', ['closed', 'rejected'])->get();    }    public function searchEnquiries(string $keyword): Collection    {        return $this->query()->where(function ($q) use ($keyword) {                $q->where('student_name', 'like', "%{$keyword}%")->orWhere('parent_name', 'like', "%{$keyword}%")->orWhere('parent_phone', 'like', "%{$keyword}%")->orWhere('parent_email', 'like', "%{$keyword}%");            })->get();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('created_at', [$startDate, $endDate])->get();    }    public function countBySource(): Collection    {        return $this->query()->selectRaw('source, COUNT(*) as total')->groupBy('source')->get();    }    public function getActiveEnquiries(): Collection    {        return $this->query()->whereNotIn('status', ['closed', 'rejected'])->get();    }}